// KPICard.jsx — Power BI style KPI cards

const PALETTES = {
  default: ["#f97316","#fb923c","#22d3ee","#a78bfa","#4ade80","#f43f5e"],
  blue:    ["#0ea5e9","#38bdf8","#818cf8","#34d399","#fb923c","#f43f5e"],
  warm:    ["#ef4444","#f97316","#fbbf24","#ec4899","#f43f5e","#fb923c"],
  dark:    ["#a78bfa","#22d3ee","#4ade80","#fb7185","#fbbf24","#38bdf8"],
  green:   ["#16a34a","#4ade80","#86efac","#65a30d","#22d3ee","#a78bfa"],
  rose:    ["#f43f5e","#fb7185","#fda4af","#e11d48","#f97316","#a78bfa"],
  teal:    ["#14b8a6","#2dd4bf","#5eead4","#0d9488","#22d3ee","#4ade80"],
  gold:    ["#d97706","#f59e0b","#fbbf24","#92400e","#fb923c","#4ade80"],
};

function fmt(val) {
  if (typeof val !== "number") return val ?? "—";
  if (val >= 1_000_000) return `${(val/1_000_000).toFixed(2)}M`;
  if (val >= 1_000)     return `${(val/1_000).toFixed(1)}K`;
  return Number.isInteger(val) ? val.toLocaleString() : val.toFixed(2);
}

function deriveKPI(chart) {
  const data = chart.data || [];
  if (!data.length) return null;

  const xKey     = chart.x_axis;
  const valKeys  = Object.keys(data[0]).filter(k => k !== xKey && typeof data[0][k] === "number");
  if (!valKeys.length) return null;

  const mainKey  = valKeys[0];
  const total    = data.reduce((s, r) => s + (r[mainKey] || 0), 0);
  const avg      = total / data.length;
  const sorted   = [...data].sort((a, b) => (b[mainKey]||0) - (a[mainKey]||0));
  const topVal   = sorted[0]?.[mainKey] ?? 0;
  const topLabel = sorted[0]?.[xKey] ?? "";

  // Trend: compare last 2 values for line charts
  let trend = null, trendPct = null;
  if ((chart.chart_type === "line" || chart.chart_type === "area") && data.length >= 2) {
    const last  = data[data.length-1][mainKey];
    const prev  = data[data.length-2][mainKey];
    trend    = last >= prev ? "up" : "down";
    trendPct = prev !== 0 ? Math.abs(((last-prev)/prev)*100).toFixed(1) : 0;
  }

  return { total, avg, topVal, topLabel, count: data.length, mainKey, xKey, trend, trendPct };
}

export default function KPICard({ chart, colorSchema = "default", index = 0 }) {
  const kpi    = deriveKPI(chart);
  const colors = PALETTES[colorSchema] || PALETTES.default;
  const color  = colors[index % colors.length];

  if (!kpi) return null;

  const trendUp = kpi.trend === "up";

  return (
    <div style={{ ...S.card, animationDelay:`${index*0.06}s`, borderTop:`2px solid ${color}` }} className="fade-up">
      {/* Header */}
      <div style={S.hdr}>
        <div style={{ ...S.iconWrap, background:`${color}15`, border:`1px solid ${color}25` }}>
          <ChartTypeIcon type={chart.chart_type} color={color} />
        </div>
        <div style={S.kpiTitle}>{chart.title}</div>
      </div>

      {/* Main metric */}
      <div style={S.mainMetric}>
        <span style={{ ...S.mainVal, color }}>{fmt(kpi.total)}</span>
        <span style={S.mainLabel}>Total {kpi.mainKey.replace(/_/g," ")}</span>
      </div>

      {/* Trend badge */}
      {kpi.trend && (
        <div style={{ ...S.trendBadge, background: trendUp?"rgba(74,222,128,0.1)":"rgba(244,63,94,0.1)", border:`1px solid ${trendUp?"rgba(74,222,128,0.25)":"rgba(244,63,94,0.25)"}`, color: trendUp?"#4ade80":"#f43f5e" }}>
          <span>{trendUp?"↑":"↓"}</span>
          {kpi.trendPct}% vs previous period
        </div>
      )}

      {/* Stats row */}
      <div style={S.statsRow}>
        <div style={S.stat}>
          <span style={S.statVal}>{fmt(kpi.avg)}</span>
          <span style={S.statLbl}>Average</span>
        </div>
        <div style={S.statDiv}/>
        <div style={S.stat}>
          <span style={S.statVal}>{fmt(kpi.topVal)}</span>
          <span style={S.statLbl}>Peak</span>
        </div>
        <div style={S.statDiv}/>
        <div style={S.stat}>
          <span style={S.statVal}>{kpi.count}</span>
          <span style={S.statLbl}>Records</span>
        </div>
      </div>

      {/* Top entry */}
      {kpi.topLabel && (
        <div style={S.topEntry}>
          <span style={S.topLabel}>🏆 Top:</span>
          <span style={{ ...S.topVal, color }}>{kpi.topLabel}</span>
          <span style={S.topNum}>{fmt(kpi.topVal)}</span>
        </div>
      )}
    </div>
  );
}

function ChartTypeIcon({ type, color }) {
  const s = { stroke:color, strokeWidth:1.5, fill:"none", strokeLinecap:"round", strokeLinejoin:"round" };
  if (type === "line" || type === "area")
    return <svg width="16" height="16" viewBox="0 0 16 16"><path d="M2 12L6 6l4 4 4-6" {...s}/></svg>;
  if (type === "pie")
    return <svg width="16" height="16" viewBox="0 0 16 16"><circle cx="8" cy="8" r="6" {...s}/><path d="M8 8V2M8 8l4.2 4.2" {...s}/></svg>;
  return <svg width="16" height="16" viewBox="0 0 16 16"><rect x="2" y="8" width="3" height="5" rx="1" fill={color} opacity="0.8"/><rect x="6.5" y="5" width="3" height="8" rx="1" fill={color}/><rect x="11" y="3" width="3" height="10" rx="1" fill={color} opacity="0.6"/></svg>;
}

const S = {
  card:     { background:"var(--bg2)", border:"1px solid var(--border)", borderRadius:"var(--radius-lg)", padding:"18px 20px", display:"flex", flexDirection:"column", gap:12, transition:"border-color 0.2s" },
  hdr:      { display:"flex", alignItems:"center", gap:10 },
  iconWrap: { width:34, height:34, borderRadius:9, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 },
  kpiTitle: { fontSize:12, fontWeight:600, color:"var(--text2)", letterSpacing:"0.02em", lineHeight:1.3 },
  mainMetric:{ display:"flex", flexDirection:"column", gap:3 },
  mainVal:  { fontSize:32, fontWeight:800, letterSpacing:"-1px", fontFamily:"'Syne',sans-serif", animation:"countUp 0.5s ease forwards" },
  mainLabel:{ fontSize:11, color:"var(--text3)", textTransform:"uppercase", letterSpacing:"0.07em" },
  trendBadge:{ display:"flex", alignItems:"center", gap:5, padding:"5px 10px", borderRadius:20, fontSize:11, fontWeight:600, width:"fit-content" },
  statsRow: { display:"flex", alignItems:"center", gap:0, background:"var(--bg3)", borderRadius:"var(--radius)", overflow:"hidden" },
  stat:     { flex:1, padding:"10px 12px", display:"flex", flexDirection:"column", alignItems:"center", gap:3 },
  statVal:  { fontSize:14, fontWeight:700, color:"var(--text)" },
  statLbl:  { fontSize:10, color:"var(--text3)", textTransform:"uppercase", letterSpacing:"0.06em" },
  statDiv:  { width:1, height:36, background:"var(--border)" },
  topEntry: { display:"flex", alignItems:"center", gap:8, padding:"8px 12px", background:"var(--bg3)", borderRadius:"var(--radius)", overflow:"hidden" },
  topLabel: { fontSize:11, color:"var(--text3)", flexShrink:0 },
  topVal:   { fontSize:12, fontWeight:600, flex:1, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" },
  topNum:   { fontSize:12, color:"var(--text2)", fontWeight:500, flexShrink:0 },
};
